const body = $json.body || $json;
return [{
  json: {
    message: body.message || '',
    session_id: body.session_id || '',
    context: body.context || '',
    start_time: Date.now()
  }
}];

const response = $json;
const content = response.message?.content || response.response || '';
const sessionId = $('Extract Input').first().json.session_id;
const originalMessage = $('Extract Input').first().json.message;

let agent = 'general';
let confidence = 0;

try {
  let jsonStr = content;
  const codeBlockMatch = content.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (codeBlockMatch) {
    jsonStr = codeBlockMatch[1];
  } else {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) jsonStr = jsonMatch[0];
  }

  const parsed = JSON.parse(jsonStr);
  agent = parsed.agent || 'general';
  confidence = parseFloat(parsed.confidence) || 0;
} catch (e) {
  agent = 'general';
  confidence = 0;
}

const validAgents = ['docmentor', 'review', 'digest', 'file', 'general'];
if (!validAgents.includes(agent)) agent = 'general';

return [{
  json: {
    agent: agent,
    confidence: confidence,
    session_id: sessionId,
    original_message: originalMessage,
    start_time: $('Extract Input').first().json.start_time
  }
}];

