={{ JSON.stringify({
  text: (() => {
    const msg = $('Parse Intent').first().json.original_message;
    const prefixes = ['analyze this review:', 'review this:', 'analyze:', 'review:'];
    let text = msg;
    for (const p of prefixes) {
      if (text.toLowerCase().startsWith(p)) {
        text = text.substring(p.length).trim();
        break;
      }
    }
    return text;
  })(),
  type: 'restaurant'
}) }}

