return [{
  json: {
    agent_response: 'To upload and process files, please use the File Manager page. You can drag and drop files there or click to browse. Supported formats: PDF, TXT, MD, CSV, JSON.',
    agent: 'file'
  }
}];

const agent = $('Parse Intent').first().json.agent;
const sessionId = $('Parse Intent').first().json.session_id;
const data = $json;

let response = '';
let extraFields = {};

if (agent === 'docmentor') {
  if (data.job_id) {
    response = 'Your question is being processed. Please wait...';
    extraFields = { job_id: data.job_id, status: data.status || 'processing' };
  } else {
    response = data.response || 'DocMentor is processing your request.';
  }
} else if (agent === 'review') {
  if (data.sentiment && data.summary) {
    response = data.summary;
    extraFields = {
      sentiment: data.sentiment,
      sentiment_score: data.sentiment_score,
      key_themes: data.key_themes,
      pros: data.pros,
      cons: data.cons,
      predicted_rating: data.predicted_rating
    };
  } else {
    response = data.summary || JSON.stringify(data);
  }
} else if (agent === 'digest') {
  if (data.content) {
    response = 'Here is your latest digest. Check the Digest page for the full content.';
  } else {
    response = 'No digests found. Configure one on the Digest page.';
  }
} else if (agent === 'file') {
  response = data.agent_response || 'Please use the File Manager page to upload files.';
} else {
  response = data.message?.content || data.response || "I'm not sure how to help with that. Try asking about your documents, reviews, or digests.";
}

return [{
  json: {
    agent: agent,
    response: response,
    session_id: sessionId,
    ...extraFields
  }
}];

return [{
  json: {
    agent: "none",
    response: "I'm not confident enough to route this to a specific agent. Your request has been flagged for human review.",
    session_id: $('Parse Intent').first().json.session_id
  }
}];

